package com.google.gson.examples.android.model;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.lang.reflect.Constructor;
import java.lang.reflect.InvocationTargetException;
import java.util.Collections;
import java.util.List;

import org.junit.jupiter.api.Test;

class CartTest {

  static class LineItem {}

  @Test
  void testGetBuyerName() throws Exception {
    List<LineItem> lineItems = Collections.emptyList();
    String buyerName = "John Doe";
    String creditCard = "1234-5678-9876-5432";

    // Use reflection to create an instance of Cart
    Class<?> cartClass = Class.forName("com.google.gson.examples.android.model.Cart");

    Constructor<?> constructor = cartClass.getConstructor(List.class, String.class, String.class);
    Object cart = constructor.newInstance(lineItems, buyerName, creditCard);

    String result = (String) cartClass.getMethod("getBuyerName").invoke(cart);

    assertEquals(buyerName, result);
  }
}
